fun process(obj: Any) {
    if (obj !is String) {
        println("Not a string")
        return
    }
    println(obj.length)
}
process(42)
process("hello")

val obj: Any? = "Kotlin"
if (obj != null && obj is String) {
    println(obj.uppercase())
}

fun toIntSafe(obj: Any): Int {
    return (obj as? Int) ?: -1
}
println(toIntSafe(42))
println(toIntSafe("hello"))
